import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Member {
  id: string;
  firstName: string;
  lastName: string;
  email: string;
  phone: string;
  birthDate: string;
  address: string;
  registrationDate: string;
  photoUrl?: string;
}

export enum AppView {
  REGISTRATION = 'registration',
  CARD_GENERATOR = 'card_generator'
}

import React, { useState, useEffect } from 'react';
import RegistrationApp from './components/RegistrationApp';
import CardGeneratorApp from './components/CardGeneratorApp';
import { AppView, Member } from './types';
import { LayoutGrid, UserPlus, CreditCard } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.REGISTRATION);
  const [members, setMembers] = useState<Member[]>([]);

  // Load members from localStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem('political_party_members');
    if (saved) {
      try {
        setMembers(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load members", e);
      }
    }
  }, []);

  // Save members whenever they change
  useEffect(() => {
    localStorage.setItem('political_party_members', JSON.stringify(members));
  }, [members]);

  const addMember = (member: Member) => {
    setMembers(prev => [...prev, member]);
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Navigation Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50 no-print">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            <div className="flex items-center gap-2">
              <div className="bg-blue-600 p-2 rounded-lg">
                <LayoutGrid className="text-white w-6 h-6" />
              </div>
              <h1 className="text-xl font-bold text-slate-800">Parti National</h1>
            </div>

            <nav className="flex gap-1 bg-slate-100 p-1 rounded-xl">
              <button
                onClick={() => setView(AppView.REGISTRATION)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                  view === AppView.REGISTRATION 
                  ? 'bg-white text-blue-600 shadow-sm' 
                  : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                <UserPlus size={18} />
                Enregistrement
              </button>
              <button
                onClick={() => setView(AppView.CARD_GENERATOR)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                  view === AppView.CARD_GENERATOR 
                  ? 'bg-white text-blue-600 shadow-sm' 
                  : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                <CreditCard size={18} />
                Générateur de Cartes
              </button>
            </nav>
          </div>
        </div>
      </header>

      <main className="flex-grow max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8">
        {view === AppView.REGISTRATION ? (
          <RegistrationApp onAddMember={addMember} />
        ) : (
          <CardGeneratorApp members={members} />
        )}
      </main>

      <footer className="bg-white border-t border-slate-200 py-6 no-print">
        <div className="max-w-7xl mx-auto px-4 text-center text-slate-500 text-sm">
          &copy; {new Date().getFullYear()} Système de Gestion de Parti Politique. Conçu avec expertise.
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Member } from '../types';
import { QRCodeSVG } from 'qrcode.react';
import { UserPlus, CheckCircle, Download, User } from 'lucide-react';

interface RegistrationAppProps {
  onAddMember: (member: Member) => void;
}

const RegistrationApp: React.FC<RegistrationAppProps> = ({ onAddMember }) => {
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    birthDate: '',
    address: '',
  });
  const [lastRegistered, setLastRegistered] = useState<Member | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const generateId = () => {
    const year = new Date().getFullYear().toString().slice(-2);
    const random = Math.floor(1000 + Math.random() * 9000);
    return `PN-${year}-${random}`;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    // Simulate small delay for UX
    setTimeout(() => {
      const newMember: Member = {
        ...formData,
        id: generateId(),
        registrationDate: new Date().toISOString(),
        photoUrl: `https://picsum.photos/seed/${formData.lastName}/200/200`
      };

      onAddMember(newMember);
      setLastRegistered(newMember);
      setFormData({
        firstName: '',
        lastName: '',
        email: '',
        phone: '',
        birthDate: '',
        address: '',
      });
      setIsSubmitting(false);
    }, 800);
  };

  return (
    <div className="max-w-4xl mx-auto">
      <div className="grid md:grid-cols-2 gap-8">
        {/* Form Section */}
        <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex items-center gap-3 mb-6">
            <div className="bg-blue-100 p-2 rounded-lg text-blue-600">
              <UserPlus size={24} />
            </div>
            <h2 className="text-2xl font-bold text-slate-800">Nouveau Membre</h2>
          </div>

          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Prénom</label>
                <input
                  required
                  type="text"
                  value={formData.firstName}
                  onChange={e => setFormData({...formData, firstName: e.target.value})}
                  className="w-full px-4 py-2 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                  placeholder="Jean"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Nom</label>
                <input
                  required
                  type="text"
                  value={formData.lastName}
                  onChange={e => setFormData({...formData, lastName: e.target.value})}
                  className="w-full px-4 py-2 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                  placeholder="Dupont"
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Email</label>
              <input
                required
                type="email"
                value={formData.email}
                onChange={e => setFormData({...formData, email: e.target.value})}
                className="w-full px-4 py-2 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                placeholder="jean.dupont@example.com"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Téléphone</label>
              <input
                required
                type="tel"
                value={formData.phone}
                onChange={e => setFormData({...formData, phone: e.target.value})}
                className="w-full px-4 py-2 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                placeholder="+243 ..."
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Date de Naissance</label>
              <input
                required
                type="date"
                value={formData.birthDate}
                onChange={e => setFormData({...formData, birthDate: e.target.value})}
                className="w-full px-4 py-2 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Adresse</label>
              <textarea
                required
                rows={2}
                value={formData.address}
                onChange={e => setFormData({...formData, address: e.target.value})}
                className="w-full px-4 py-2 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                placeholder="123 Rue de la Liberté, Kinshasa"
              />
            </div>

            <button
              disabled={isSubmitting}
              type="submit"
              className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-xl shadow-lg shadow-blue-200 transition-all flex justify-center items-center gap-2"
            >
              {isSubmitting ? 'Enregistrement...' : 'Enregistrer le Membre'}
            </button>
          </form>
        </div>

        {/* Success / Result Section */}
        <div className="flex flex-col gap-6">
          {lastRegistered ? (
            <div className="bg-emerald-50 border border-emerald-200 p-8 rounded-2xl animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="flex items-center gap-2 text-emerald-600 mb-4">
                <CheckCircle size={24} />
                <h3 className="text-xl font-bold">Enregistré avec succès !</h3>
              </div>

              <div className="bg-white p-6 rounded-xl border border-emerald-100 flex flex-col items-center">
                <p className="text-sm text-slate-500 mb-2 font-medium uppercase tracking-wider">ID Membre Unique</p>
                <div className="text-3xl font-black text-slate-900 mb-6 font-mono tracking-tighter">
                  {lastRegistered.id}
                </div>

                <div className="bg-white p-4 border-2 border-slate-100 rounded-2xl mb-6">
                  <QRCodeSVG 
                    value={JSON.stringify({
                      id: lastRegistered.id,
                      n: `${lastRegistered.firstName} ${lastRegistered.lastName}`,
                      e: lastRegistered.email
                    })} 
                    size={180}
                    level="H"
                    includeMargin={true}
                  />
                </div>

                <div className="text-center">
                  <p className="font-bold text-slate-800">{lastRegistered.firstName} {lastRegistered.lastName}</p>
                  <p className="text-sm text-slate-500">Scannez ce code pour générer la carte</p>
                </div>

                <button 
                  onClick={() => window.print()}
                  className="mt-6 flex items-center gap-2 text-blue-600 font-semibold hover:underline no-print"
                >
                  <Download size={18} />
                  Imprimer le reçu
                </button>
              </div>
            </div>
          ) : (
            <div className="bg-slate-100 border-2 border-dashed border-slate-300 h-full rounded-2xl flex flex-col items-center justify-center text-slate-400 p-12 text-center">
              <User size={64} strokeWidth={1} className="mb-4" />
              <p className="text-lg font-medium">En attente d'enregistrement</p>
              <p className="text-sm">Remplissez le formulaire pour générer un ID unique et un QR Code.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default RegistrationApp;

import React, { useState, useEffect, useRef } from 'react';
import { Member } from '../types';
import { Search, QrCode, CreditCard, Printer, UserCircle, X } from 'lucide-react';
import { QRCodeSVG } from 'qrcode.react';

interface CardGeneratorAppProps {
  members: Member[];
}

const CardGeneratorApp: React.FC<CardGeneratorAppProps> = ({ members }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedMember, setSelectedMember] = useState<Member | null>(null);
  const [showScanner, setShowScanner] = useState(false);

  // Filtering members based on ID or Full Name
  const filteredMembers = members.filter(m => 
    m.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
    `${m.firstName} ${m.lastName}`.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleSelect = (member: Member) => {
    setSelectedMember(member);
    setSearchTerm('');
  };

  // Mock QR Scanner (since we can't easily implement a full camera decoder in this single-file environment 
  // without external heavy scripts like html5-qrcode, we provide a "manual" simulation for demonstration)
  const simulateScan = () => {
    if (members.length === 0) {
      alert("Aucun membre enregistré pour simuler un scan.");
      return;
    }
    const randomMember = members[Math.floor(Math.random() * members.length)];
    setSelectedMember(randomMember);
    setShowScanner(false);
  };

  return (
    <div className="max-w-6xl mx-auto">
      <div className="grid lg:grid-cols-3 gap-8">

        {/* Left Column: Search & Selection */}
        <div className="lg:col-span-1 space-y-6 no-print">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
              <Search size={20} className="text-blue-500" />
              Rechercher un membre
            </h3>

            <div className="space-y-4">
              <div className="relative">
                <input
                  type="text"
                  placeholder="ID (PN-...) ou Nom..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="w-full pl-10 pr-4 py-2 rounded-xl border border-slate-300 focus:ring-2 focus:ring-blue-500 outline-none"
                />
                <Search className="absolute left-3 top-2.5 text-slate-400" size={18} />
              </div>

              <button 
                onClick={() => setShowScanner(true)}
                className="w-full flex items-center justify-center gap-2 bg-slate-800 hover:bg-slate-900 text-white py-2 rounded-xl transition-colors font-medium"
              >
                <QrCode size={18} />
                Scanner un QR Code
              </button>
            </div>
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-4 border-b border-slate-100 bg-slate-50">
              <h4 className="font-semibold text-slate-700 text-sm uppercase tracking-wider">Membres ({filteredMembers.length})</h4>
            </div>
            <div className="max-h-[400px] overflow-y-auto">
              {filteredMembers.length > 0 ? (
                filteredMembers.map(m => (
                  <button
                    key={m.id}
                    onClick={() => handleSelect(m)}
                    className={`w-full text-left p-4 flex items-center gap-3 border-b border-slate-50 transition-colors ${selectedMember?.id === m.id ? 'bg-blue-50' : 'hover:bg-slate-50'}`}
                  >
                    <div className="bg-slate-200 w-10 h-10 rounded-full flex items-center justify-center text-slate-500 overflow-hidden">
                      {m.photoUrl ? <img src={m.photoUrl} alt="Avatar" className="w-full h-full object-cover" /> : <UserCircle />}
                    </div>
                    <div>
                      <p className="font-bold text-slate-800 leading-none">{m.firstName} {m.lastName}</p>
                      <p className="text-xs text-slate-500 mt-1">{m.id}</p>
                    </div>
                  </button>
                ))
              ) : (
                <div className="p-8 text-center text-slate-400 italic text-sm">
                  Aucun membre trouvé
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Right Column: Card Preview */}
        <div className="lg:col-span-2">
          {selectedMember ? (
            <div className="flex flex-col items-center gap-8">
              {/* Card UI */}
              <div className="relative w-full max-w-[500px] aspect-[1.6/1] bg-gradient-to-br from-blue-700 to-indigo-900 rounded-3xl p-8 shadow-2xl text-white overflow-hidden border-4 border-white/10 group">
                {/* Background Decorations */}
                <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-bl-full blur-2xl"></div>
                <div className="absolute bottom-0 left-0 w-48 h-48 bg-blue-400/20 rounded-tr-full blur-3xl"></div>

                <div className="relative z-10 flex flex-col h-full justify-between">
                  <div className="flex justify-between items-start">
                    <div>
                      <h2 className="text-2xl font-black uppercase tracking-tight italic">Parti National</h2>
                      <p className="text-xs font-medium text-blue-200 tracking-[0.2em] uppercase">Mouvement pour le Progrès</p>
                    </div>
                    <div className="bg-white/10 p-1 rounded-lg backdrop-blur-md">
                      <div className="bg-white p-1 rounded">
                        <QRCodeSVG 
                          value={selectedMember.id} 
                          size={50} 
                          level="M"
                        />
                      </div>
                    </div>
                  </div>

                  <div className="flex items-center gap-6 mt-4">
                    <div className="w-24 h-24 bg-white/20 rounded-2xl overflow-hidden border-2 border-white/50 shadow-inner">
                      <img src={selectedMember.photoUrl} alt="Portrait" className="w-full h-full object-cover" />
                    </div>
                    <div className="flex-1">
                      <h3 className="text-2xl font-bold truncate">{selectedMember.firstName} {selectedMember.lastName}</h3>
                      <p className="text-sm font-medium text-blue-200">Membre Certifié</p>
                      <div className="mt-4 grid grid-cols-2 gap-2">
                        <div>
                          <p className="text-[10px] text-white/60 uppercase">Identifiant</p>
                          <p className="text-sm font-mono font-bold tracking-tight">{selectedMember.id}</p>
                        </div>
                        <div>
                          <p className="text-[10px] text-white/60 uppercase">Date d'adhésion</p>
                          <p className="text-sm font-bold">{new Date(selectedMember.registrationDate).toLocaleDateString()}</p>
                        </div>
                      </div>
                    </div>
                  </div>

                  <div className="pt-4 border-t border-white/10 flex justify-between items-end">
                    <p className="text-[9px] font-light text-white/40 italic">Signature de la Présidence</p>
                    <div className="h-6 border-b border-white/20 w-32"></div>
                  </div>
                </div>

                {/* Card Brand Overlay */}
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 rotate-[15deg] opacity-5 pointer-events-none text-8xl font-black">
                  PN
                </div>
              </div>

              {/* Actions */}
              <div className="flex gap-4 no-print">
                <button 
                  onClick={() => window.print()}
                  className="bg-white border border-slate-200 hover:border-blue-500 hover:text-blue-600 text-slate-700 font-bold py-3 px-8 rounded-2xl shadow-sm transition-all flex items-center gap-2"
                >
                  <Printer size={20} />
                  Imprimer la Carte
                </button>
                <button 
                  onClick={() => setSelectedMember(null)}
                  className="bg-slate-100 hover:bg-slate-200 text-slate-500 font-bold py-3 px-8 rounded-2xl transition-all"
                >
                  Fermer
                </button>
              </div>
            </div>
          ) : (
            <div className="h-[400px] bg-slate-50 border-2 border-dashed border-slate-200 rounded-3xl flex flex-col items-center justify-center text-slate-400 p-12 text-center no-print">
              <div className="bg-white p-4 rounded-full shadow-sm mb-4">
                <CreditCard size={48} className="text-slate-200" />
              </div>
              <h3 className="text-xl font-bold text-slate-600">Sélectionnez un membre</h3>
              <p className="text-sm max-w-xs mt-2">Recherchez par nom ou scannez le QR code du membre pour générer et visualiser sa carte officielle.</p>
            </div>
          )}
        </div>

      </div>

      {/* QR Scanner Modal (Simulated) */}
      {showScanner && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/80 backdrop-blur-sm p-4 no-print">
          <div className="bg-white w-full max-w-md rounded-3xl overflow-hidden shadow-2xl">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <h3 className="font-bold text-slate-800 flex items-center gap-2">
                <QrCode size={20} className="text-blue-600" />
                Scanner le Code
              </h3>
              <button onClick={() => setShowScanner(false)} className="text-slate-400 hover:text-slate-600 transition-colors">
                <X size={24} />
              </button>
            </div>
            <div className="p-12 flex flex-col items-center">
              <div className="relative w-64 h-64 border-4 border-blue-500 rounded-3xl flex items-center justify-center group">
                <div className="absolute inset-0 bg-blue-500/5 group-hover:bg-blue-500/10 transition-colors"></div>
                <QrCode size={80} className="text-blue-200 animate-pulse" />

                {/* Corner Accents */}
                <div className="absolute -top-2 -left-2 w-8 h-8 border-t-4 border-l-4 border-blue-600 rounded-tl-xl"></div>
                <div className="absolute -top-2 -right-2 w-8 h-8 border-t-4 border-r-4 border-blue-600 rounded-tr-xl"></div>
                <div className="absolute -bottom-2 -left-2 w-8 h-8 border-b-4 border-l-4 border-blue-600 rounded-bl-xl"></div>
                <div className="absolute -bottom-2 -right-2 w-8 h-8 border-b-4 border-r-4 border-blue-600 rounded-br-xl"></div>

                {/* Scanning line animation */}
                <div className="absolute w-full h-1 bg-blue-500 shadow-[0_0_15px_rgba(59,130,246,0.8)] animate-[scan_2s_ease-in-out_infinite]"></div>
              </div>

              <div className="mt-8 text-center space-y-4">
                <p className="text-slate-500 text-sm">Positionnez le QR code au centre du cadre</p>
                <button 
                  onClick={simulateScan}
                  className="bg-blue-600 text-white px-8 py-3 rounded-2xl font-bold shadow-lg shadow-blue-200 hover:bg-blue-700 transition-all active:scale-95"
                >
                  Simuler la Lecture (Auto-détection)
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Global Print Styles */}
      <style>{`
        @keyframes scan {
          0%, 100% { top: 0%; }
          50% { top: 100%; }
        }
        @media print {
          body { background: white; }
          .no-print { display: none !important; }
          main { padding: 0 !important; }
          .lg\\:col-span-2 { width: 100% !important; display: flex !important; justify-content: center !important; }
        }
      `}</style>
    </div>
  );
};

