import React, { useState, useEffect } from 'react';
import RegistrationApp from './components/RegistrationApp';
import CardGeneratorApp from './components/CardGeneratorApp';
import { AppView, Member } from './types';
import { LayoutGrid, UserPlus, CreditCard } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.REGISTRATION);
  const [members, setMembers] = useState<Member[]>([]);

  useEffect(() => {
    const saved = localStorage.getItem('political_party_members');
    if (saved) {
      try {
        setMembers(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load members", e);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('political_party_members', JSON.stringify(members));
  }, [members]);

  const addMember = (member: Member) => {
    setMembers(prev => [...prev, member]);
  };

  return (
    <div className="min-h-screen flex flex-col">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50 no-print">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            <div className="flex items-center gap-2">
              <div className="bg-red-600 p-2 rounded-lg">
                <LayoutGrid className="text-white w-6 h-6" />
              </div>
              <h1 className="text-xl font-bold text-slate-800">UDPS - Gestion Membres</h1>
            </div>

            <nav className="flex gap-1 bg-slate-100 p-1 rounded-xl">
              <button
                onClick={() => setView(AppView.REGISTRATION)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                  view === AppView.REGISTRATION 
                  ? 'bg-white text-red-600 shadow-sm' 
                  : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                <UserPlus size={18} />
                Enregistrement
              </button>
              <button
                onClick={() => setView(AppView.CARD_GENERATOR)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                  view === AppView.CARD_GENERATOR 
                  ? 'bg-white text-red-600 shadow-sm' 
                  : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                <CreditCard size={18} />
                Cartes PVC
              </button>
            </nav>
          </div>
        </div>
      </header>

      <main className="flex-grow max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8">
        {view === AppView.REGISTRATION ? (
          <RegistrationApp onAddMember={addMember} />
        ) : (
          <CardGeneratorApp members={members} />
        )}
      </main>

      <footer className="bg-white border-t border-slate-200 py-6 no-print">
        <div className="max-w-7xl mx-auto px-4 text-center text-slate-500 text-sm">
          &copy; {new Date().getFullYear()} Union pour la Démocratie et le Progrès Social (UDPS).
        </div>
      </footer>
    </div>
  );
};

export default App;

