import React, { useState, useRef, useEffect } from 'react';
import { Member } from '../types';
import { QRCodeSVG } from 'qrcode.react';
import { UserPlus, CheckCircle, Download, User, Camera, Mail, MessageCircle, RotateCcw } from 'lucide-react';

interface RegistrationAppProps {
  onAddMember: (member: Member) => void;
}

const RegistrationApp: React.FC<RegistrationAppProps> = ({ onAddMember }) => {
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    birthDate: '',
    address: '',
  });
  const [photo, setPhoto] = useState<string | null>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [lastRegistered, setLastRegistered] = useState<Member | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' } });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        setIsCameraActive(true);
      }
    } catch (err) {
      alert("Impossible d'accéder à la caméra. Veuillez vérifier les permissions.");
    }
  };

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
      tracks.forEach(track => track.stop());
      setIsCameraActive(false);
    }
  };

  const takePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      if (context) {
        canvasRef.current.width = videoRef.current.videoWidth;
        canvasRef.current.height = videoRef.current.videoHeight;
        context.drawImage(videoRef.current, 0, 0);
        const dataUrl = canvasRef.current.toDataURL('image/jpeg');
        setPhoto(dataUrl);
        stopCamera();
      }
    }
  };

  const generateId = () => {
    const year = new Date().getFullYear();
    const random = Math.floor(1000 + Math.random() * 9000);
    return `UDPS-${year}-${random}`;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!photo) {
      alert("Veuillez prendre une photo du membre.");
      return;
    }
    setIsSubmitting(true);

    setTimeout(() => {
      const newMember: Member = {
        ...formData,
        id: generateId(),
        registrationDate: new Date().toISOString(),
        photoUrl: photo
      };

      onAddMember(newMember);
      setLastRegistered(newMember);
      setFormData({
        firstName: '',
        lastName: '',
        email: '',
        phone: '',
        birthDate: '',
        address: '',
      });
      setPhoto(null);
      setIsSubmitting(false);
    }, 800);
  };

  const shareWhatsApp = () => {
    if (!lastRegistered) return;
    const text = encodeURIComponent(`Bonjour ${lastRegistered.firstName}, votre adhésion à l'UDPS est confirmée. Matricule: ${lastRegistered.id}. Présentez ce code pour votre carte PVC.`);
    window.open(`https://wa.me/${lastRegistered.phone.replace(/\+/g, '')}?text=${text}`, '_blank');
  };

  const shareEmail = () => {
    if (!lastRegistered) return;
    const subject = encodeURIComponent("Confirmation d'adhésion UDPS");
    const body = encodeURIComponent(`Bonjour ${lastRegistered.firstName},\n\nVotre adhésion est validée.\nMatricule: ${lastRegistered.id}\n\nLe Peuple d'Abord !`);
    window.location.href = `mailto:${lastRegistered.email}?subject=${subject}&body=${body}`;
  };

  return (
    <div className="max-w-5xl mx-auto">
      <div className="grid md:grid-cols-2 gap-8">
        {/* FORMULAIRE */}
        <div className="bg-white p-6 md:p-8 rounded-3xl shadow-sm border border-slate-200">
          <div className="flex items-center gap-3 mb-6">
            <div className="bg-red-100 p-2 rounded-xl text-red-600">
              <UserPlus size={24} />
            </div>
            <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tighter">Adhésion Combattant</h2>
          </div>

          <form onSubmit={handleSubmit} className="space-y-4">
            {/* Section Photo */}
            <div className="mb-6">
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Photo d'identité (Biométrie)</label>
              <div className="relative aspect-video bg-slate-100 rounded-2xl overflow-hidden border-2 border-dashed border-slate-300 flex items-center justify-center">
                {photo ? (
                  <div className="relative w-full h-full">
                    <img src={photo} className="w-full h-full object-cover" alt="Capture" />
                    <button 
                      type="button"
                      onClick={() => setPhoto(null)}
                      className="absolute top-2 right-2 bg-red-600 text-white p-2 rounded-full shadow-lg"
                    >
                      <RotateCcw size={16} />
                    </button>
                  </div>
                ) : isCameraActive ? (
                  <div className="relative w-full h-full">
                    <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
                    <button 
                      type="button"
                      onClick={takePhoto}
                      className="absolute bottom-4 left-1/2 -translate-x-1/2 bg-red-600 text-white px-6 py-2 rounded-full font-bold shadow-xl flex items-center gap-2"
                    >
                      <Camera size={18} /> Capturer
                    </button>
                  </div>
                ) : (
                  <button 
                    type="button"
                    onClick={startCamera}
                    className="flex flex-col items-center gap-2 text-slate-400 hover:text-red-500 transition-colors"
                  >
                    <Camera size={40} />
                    <span className="text-sm font-bold uppercase">Activer la Caméra</span>
                  </button>
                )}
              </div>
              <canvas ref={canvasRef} className="hidden" />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <input
                required
                type="text"
                placeholder="Prénom"
                value={formData.firstName}
                onChange={e => setFormData({...formData, firstName: e.target.value})}
                className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-red-500 outline-none"
              />
              <input
                required
                type="text"
                placeholder="Nom"
                value={formData.lastName}
                onChange={e => setFormData({...formData, lastName: e.target.value})}
                className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-red-500 outline-none"
              />
            </div>

            <input
              required
              type="tel"
              placeholder="Téléphone (ex: +243...)"
              value={formData.phone}
              onChange={e => setFormData({...formData, phone: e.target.value})}
              className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-red-500 outline-none"
            />

            <input
              type="email"
              placeholder="Email"
              value={formData.email}
              onChange={e => setFormData({...formData, email: e.target.value})}
              className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-red-500 outline-none"
            />

            <textarea
              required
              rows={2}
              placeholder="Adresse de résidence"
              value={formData.address}
              onChange={e => setFormData({...formData, address: e.target.value})}
              className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-red-500 outline-none"
            />

            <button
              disabled={isSubmitting}
              type="submit"
              className="w-full bg-red-600 hover:bg-red-700 text-white font-black py-4 rounded-2xl shadow-lg transition-all uppercase tracking-widest flex justify-center items-center gap-2"
            >
              {isSubmitting ? 'Finalisation...' : 'Valider l\'Adhésion'}
            </button>
          </form>
        </div>

        {/* RESULTAT & PARTAGE */}
        <div className="flex flex-col gap-6">
          {lastRegistered ? (
            <div className="bg-emerald-50 border border-emerald-200 p-8 rounded-3xl animate-in fade-in slide-in-from-right-4 duration-500">
              <div className="flex items-center gap-2 text-emerald-600 mb-6">
                <CheckCircle size={28} />
                <h3 className="text-2xl font-black uppercase tracking-tighter">Confirmation</h3>
              </div>

              <div className="bg-white p-6 rounded-2xl border border-emerald-100 flex flex-col items-center shadow-sm">
                <div className="w-20 h-20 rounded-full overflow-hidden mb-4 border-2 border-red-500">
                  <img src={lastRegistered.photoUrl} className="w-full h-full object-cover" alt="Membre" />
                </div>

                <p className="text-[10px] text-slate-400 font-bold uppercase">Matricule UDPS</p>
                <div className="text-3xl font-black text-slate-900 mb-6 font-mono tracking-tighter">
                  {lastRegistered.id}
                </div>

                <div className="bg-white p-4 border-2 border-slate-100 rounded-2xl mb-6">
                  <QRCodeSVG value={lastRegistered.id} size={160} level="H" />
                </div>

                <div className="text-center mb-8">
                  <p className="font-black text-slate-800 text-xl uppercase leading-none">{lastRegistered.firstName} {lastRegistered.lastName}</p>
                </div>

                {/* Boutons de Partage */}
                <div className="grid grid-cols-3 gap-3 w-full no-print">
                  <button 
                    onClick={() => window.print()}
                    className="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-slate-50 hover:bg-slate-100 text-slate-600 transition-colors"
                  >
                    <Download size={20} />
                    <span className="text-[10px] font-bold uppercase">Imprimer</span>
                  </button>
                  <button 
                    onClick={shareWhatsApp}
                    className="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-emerald-50 hover:bg-emerald-100 text-emerald-600 transition-colors"
                  >
                    <MessageCircle size={20} />
                    <span className="text-[10px] font-bold uppercase">WhatsApp</span>
                  </button>
                  <button 
                    onClick={shareEmail}
                    className="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-blue-50 hover:bg-blue-100 text-blue-600 transition-colors"
                  >
                    <Mail size={20} />
                    <span className="text-[10px] font-bold uppercase">Email</span>
