import React, { useState, useRef } from 'react';
import { Member } from '../types';
import { QRCodeSVG } from 'qrcode.react';
import { UserPlus, CheckCircle, Download, User, Camera, Mail, MessageCircle, RotateCcw, XCircle } from 'lucide-react';

interface RegistrationAppProps {
  onAddMember: (member: Member) => void;
}

const RegistrationApp: React.FC<RegistrationAppProps> = ({ onAddMember }) => {
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    birthDate: '',
    address: '',
  });
  const [photo, setPhoto] = useState<string | null>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [lastRegistered, setLastRegistered] = useState<Member | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { 
          facingMode: 'user',
          width: { ideal: 1280 },
          height: { ideal: 720 }
        } 
      });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        setIsCameraActive(true);
      }
    } catch (err) {
      alert("Impossible d'accéder à la caméra. Veuillez vérifier les permissions dans votre navigateur.");
    }
  };

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
      tracks.forEach(track => track.stop());
      setIsCameraActive(false);
    }
  };

  const takePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      if (context) {
        const video = videoRef.current;
        const canvas = canvasRef.current;

        // Format portrait optimisé pour carte d'identité (Ratio 4:5)
        canvas.width = 480;
        canvas.height = 600;

        // Calcul du crop pour centrer le visage
        const videoRatio = video.videoWidth / video.videoHeight;
        const canvasRatio = canvas.width / canvas.height;

        let sourceX = 0, sourceY = 0, sourceWidth = video.videoWidth, sourceHeight = video.videoHeight;

        if (videoRatio > canvasRatio) {
          sourceWidth = video.videoHeight * canvasRatio;
          sourceX = (video.videoWidth - sourceWidth) / 2;
        } else {
          sourceHeight = video.videoWidth / canvasRatio;
          sourceY = (video.videoHeight - sourceHeight) / 2;
        }

        context.drawImage(
          video,
          sourceX, sourceY, sourceWidth, sourceHeight,
          0, 0, canvas.width, canvas.height
        );

        const dataUrl = canvas.toDataURL('image/jpeg', 0.85);
        setPhoto(dataUrl); // La photo est stockée dans le state pour l'enregistrement final
        stopCamera();
      }
    }
  };

  const generateId = () => {
    const year = new Date().getFullYear();
    const random = Math.floor(100000 + Math.random() * 899999);
    return `UDPS-${year}-${random}`;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!photo) {
      alert("La capture d'une photo biométrique est obligatoire.");
      return;
    }
    setIsSubmitting(true);

    // Simulation de traitement serveur
    setTimeout(() => {
      const newMember: Member = {
        ...formData,
        id: generateId(),
        registrationDate: new Date().toISOString(),
        photoUrl: photo // Enregistrement définitif de la photo prise
      };

      onAddMember(newMember);
      setLastRegistered(newMember);

      // Reset du formulaire
      setFormData({
        firstName: '',
        lastName: '',
        email: '',
        phone: '',
        birthDate: '',
        address: '',
      });
      setPhoto(null);
      setIsSubmitting(false);
    }, 1000);
  };

  const shareWhatsApp = () => {
    if (!lastRegistered) return;
    const text = encodeURIComponent(`Félicitations combattant(e) ${lastRegistered.firstName} ${lastRegistered.lastName} ! Votre adhésion à l'UDPS est confirmée. Matricule: ${lastRegistered.id}. Le Peuple d'Abord !`);
    window.open(`https://wa.me/${lastRegistered.phone.replace(/[^0-9]/g, '')}?text=${text}`, '_blank');
  };

  const shareEmail = () => {
    if (!lastRegistered) return;
    const subject = encodeURIComponent("Confirmation d'adhésion UDPS");
    const body = encodeURIComponent(`Bonjour ${lastRegistered.firstName},\n\nNous confirmons votre adhésion à l'UDPS.\n\nMatricule : ${lastRegistered.id}\n\nPrésentez ce matricule au siège pour retirer votre carte PVC.\n\nLe Peuple d'Abord !`);
    window.location.href = `mailto:${lastRegistered.email}?subject=${subject}&body=${body}`;
  };

  return (
    <div className="max-w-5xl mx-auto pb-12">
      <div className="grid md:grid-cols-2 gap-8">
        {/* FORMULAIRE */}
        <div className="bg-white p-6 md:p-8 rounded-3xl shadow-sm border border-slate-200">
          <div className="flex items-center gap-3 mb-6">
            <div className="bg-red-600 p-2 rounded-xl text-white">
              <UserPlus size={24} />
            </div>
            <div>
              <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tighter">Enrôlement UDPS</h2>
              <p className="text-[10px] font-bold text-red-600 uppercase tracking-widest">Le Peuple d'Abord</p>
            </div>
          </div>

          <form onSubmit={handleSubmit} className="space-y-4">
            {/* Section Capture Photo */}
            <div className="mb-6">
              <label className="block text-[11px] font-black text-slate-500 uppercase mb-2 tracking-wider">Photo d'Identification</label>
              <div className="relative aspect-[3/4] max-w-[260px] mx-auto bg-slate-100 rounded-3xl overflow-hidden border-4 border-slate-200 shadow-inner flex items-center justify-center">
                {photo ? (
                  <div className="relative w-full h-full">
                    <img src={photo} className="w-full h-full object-cover" alt="Capture Membre" />
                    <button 
                      type="button"
                      onClick={() => { setPhoto(null); startCamera(); }}
                      className="absolute bottom-4 left-1/2 -translate-x-1/2 bg-white/90 backdrop-blur-sm text-red-600 px-4 py-2 rounded-full font-bold text-xs flex items-center gap-2 shadow-xl border border-red-100"
                    >
                      <RotateCcw size={14} /> Refaire la photo
                    </button>
                  </div>
                ) : isCameraActive ? (
                  <div className="relative w-full h-full bg-black">
                    <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover scale-x-[-1]" />
                    <div className="absolute inset-0 border-[40px] border-black/30 pointer-events-none">
                      <div className="w-full h-full border-2 border-white/40 rounded-[120px] border-dashed"></div>
                    </div>
                    <div className="absolute bottom-6 left-0 right-0 flex justify-center gap-4">
                      <button 
                        type="button"
                        onClick={takePhoto}
                        className="w-16 h-16 bg-white rounded-full border-4 border-red-600 flex items-center justify-center shadow-2xl active:scale-90 transition-transform"
                      >
                        <div className="w-10 h-10 bg-red-600 rounded-full"></div>
                      </button>
                    </div>
                  </div>
                ) : (
                  <button 
                    type="button"
                    onClick={startCamera}
                    className="flex flex-col items-center gap-3 text-slate-400 hover:text-red-600 transition-all"
                  >
                    <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center shadow-md">
                      <Camera size={32} />
                    </div>
                    <span className="text-[10px] font-black uppercase tracking-widest">Prendre une photo</span>
                  </button>
                )}
              </div>
              <canvas ref={canvasRef} className="hidden" />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <input
                required
                type="text"
                placeholder="Prénom"
                value={formData.firstName}
                onChange={e => setFormData({...formData, firstName: e.target.value})}
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-red-500 outline-none transition-all"
              />
              <input
                required
                type="text"
                placeholder="Nom"
                value={formData.lastName}
                onChange={e => setFormData({...formData, lastName: e.target.value})}
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-red-500 outline-none transition-all"
              />
            </div>

            <input
              required
              type="tel"
              placeholder="Téléphone (WhatsApp)"
              value={formData.phone}
              onChange={e => setFormData({...formData, phone: e.target.value})}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-red-500 outline-none transition-all"
            />

            <input
              type="email"
              placeholder="Email (facultatif)"
              value={formData.email}
              onChange={e => setFormData({...formData, email: e.target.value})}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-red-500 outline-none transition-all"
            />

            <textarea
              required
              rows={2}
              placeholder="Adresse complète"
              value={formData.address}
              onChange={e => setFormData({...formData, address: e.target.value})}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-red-500 outline-none transition-all resize-none"
            />

            <button
              disabled={isSubmitting || (!photo && !isCameraActive && !lastRegistered)}
              type="submit"
              className="w-full bg-red-600 hover:bg-red-700 disabled:bg-slate-300 text-white font-black py-4 rounded-2xl shadow-xl transition-all uppercase tracking-[0.2em]"
            >
              {isSubmitting ? 'Enregistrement...' : 'Valider l\'Adhésion'}
            </button>
          </form>
        </div>

        {/* REÇU & PARTAGE */}
        <div className="flex flex-col gap-6">
          {lastRegistered ? (
            <div className="bg-white border border-slate-200 p-8 rounded-3xl animate-in fade-in zoom-in duration-500 shadow-xl">
              <div className="flex items-center gap-3 text-red-600 mb-6">
                <CheckCircle size={32} />
