              </div>

              <div className="flex flex-col items-center bg-slate-50 p-6 rounded-2xl border border-slate-100">
                <div className="w-24 h-24 rounded-full overflow-hidden mb-4 border-4 border-white shadow-md">
                  <img src={lastRegistered.photoUrl} className="w-full h-full object-cover" alt="Portrait Membre" />
