                <p className="text-[10px] text-slate-400 font-bold uppercase mb-1">Matricule</p>
                <div className="text-3xl font-black text-slate-900 mb-6 font-mono tracking-tighter">
                  {lastRegistered.id}
                </div>

                <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 mb-6">
                  <QRCodeSVG value={lastRegistered.id} size={150} level="H" />
                </div>

                <div className="text-center mb-6">
                  <h4 className="font-black text-slate-800 text-xl uppercase">{lastRegistered.firstName} {lastRegistered.lastName}</h4>
                  <p className="text-xs text-slate-500 mt-1 uppercase tracking-widest font-bold">UDPS - Le Peuple d'Abord</p>
                </div>

                <div className="grid grid-cols-3 gap-3 w-full no-print">
