  CARD_GENERATOR = 'card_generator'
}

export interface CentralDatabase {
  version: string;
  lastUpdated: string;
  members: Member[];
}

import React, { useState, useEffect, useCallback } from 'react';
import RegistrationApp from './components/RegistrationApp';
import CardGeneratorApp from './components/CardGeneratorApp';
import { AppView, Member, CentralDatabase } from './types';
import { LayoutGrid, UserPlus, CreditCard, Database, Shield } from 'lucide-react';

const DB_KEY = 'udps_central_database';
const DB_VERSION = '1.0.0';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.REGISTRATION);
  const [db, setDb] = useState<CentralDatabase>({
    version: DB_VERSION,
    lastUpdated: new Date().toISOString(),
    members: []
  });

  // Chargement initial de la base de données centralisée
  useEffect(() => {
    const savedDb = localStorage.getItem(DB_KEY);
    if (savedDb) {
      try {
        const parsed: CentralDatabase = JSON.parse(savedDb);
        // Migration simple si nécessaire
        if (parsed.version === DB_VERSION) {
          setDb(parsed);
        } else {
          console.warn("Ancienne version de DB détectée, migration possible ici.");
          setDb(parsed);
        }
      } catch (e) {
        console.error("Erreur de corruption de la base de données", e);
      }
    }
  }, []);

  // Sauvegarde automatique lors des changements
  useEffect(() => {
    localStorage.setItem(DB_KEY, JSON.stringify(db));
  }, [db]);

  const addMember = useCallback((member: Member) => {
    setDb(prev => ({
      ...prev,
      lastUpdated: new Date().toISOString(),
      members: [member, ...prev.members] // Les plus récents en premier
    }));
    // Optionnel: On peut basculer vers la vue carte après enregistrement
    // setView(AppView.CARD_GENERATOR);
  }, []);

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50 no-print">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-20">
            <div className="flex items-center gap-3">
              <div className="bg-red-600 p-2.5 rounded-2xl shadow-lg shadow-red-200">
                <Shield className="text-white w-7 h-7" />
              </div>
              <div>
                <h1 className="text-xl font-black text-slate-900 tracking-tighter uppercase leading-none">UDPS</h1>
                <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mt-1">Base de données Nationale</p>
              </div>
            </div>

            <nav className="flex gap-2 bg-slate-100 p-1.5 rounded-2xl">
              <button
                onClick={() => setView(AppView.REGISTRATION)}
                className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-black transition-all uppercase tracking-tighter ${
                  view === AppView.REGISTRATION 
                  ? 'bg-white text-red-600 shadow-sm' 
                  : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                <UserPlus size={18} />
                Enrôlement
              </button>
              <button
                onClick={() => setView(AppView.CARD_GENERATOR)}
                className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-black transition-all uppercase tracking-tighter ${
                  view === AppView.CARD_GENERATOR 
                  ? 'bg-white text-red-600 shadow-sm' 
                  : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                <CreditCard size={18} />
                Cartes PVC
              </button>
            </nav>

            <div className="hidden md:flex items-center gap-4 border-l border-slate-100 pl-6 ml-6">
              <div className="text-right">
                <p className="text-[10px] font-bold text-slate-400 uppercase">État de la Base</p>
                <p className="text-sm font-black text-slate-900">{db.members.length} Membres</p>
              </div>
              <div className="bg-emerald-100 p-2 rounded-full">
                <Database className="text-emerald-600 w-5 h-5" />
              </div>
            </div>
          </div>
        </div>
      </header>

      <main className="flex-grow max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8">
        {view === AppView.REGISTRATION ? (
          <RegistrationApp onAddMember={addMember} />
        ) : (
          <CardGeneratorApp members={db.members} />
        )}
      </main>

      <footer className="bg-white border-t border-slate-200 py-8 no-print">
        <div className="max-w-7xl mx-auto px-4 flex flex-col md:flex-row justify-between items-center gap-4 text-slate-500 text-[11px] font-bold uppercase tracking-widest">
          <div>&copy; {new Date().getFullYear()} Union pour la Démocratie et le Progrès Social (UDPS)</div>
          <div className="flex items-center gap-2">
            <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
            Base Synchronisée - v{db.version}
          </div>
        </div>
      </footer>
    </div>
  );
};

