import React, { useState, useRef } from 'react';
import { Member } from '../types';
import { QRCodeSVG } from 'qrcode.react';
import { UserPlus, CheckCircle, Download, User, Camera, Mail, MessageCircle, RotateCcw, CameraIcon, ShieldCheck } from 'lucide-react';

interface RegistrationAppProps {
  onAddMember: (member: Member) => void;
}

const RegistrationApp: React.FC<RegistrationAppProps> = ({ onAddMember }) => {
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    birthDate: '',
    address: '',
  });
  const [photo, setPhoto] = useState<string | null>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [lastRegistered, setLastRegistered] = useState<Member | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { 
          facingMode: 'user',
          width: { ideal: 1280 },
          height: { ideal: 720 }
        } 
      });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        setIsCameraActive(true);
      }
    } catch (err) {
      alert("Impossible d'accéder à la caméra. Veuillez vérifier les permissions.");
    }
  };

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
      tracks.forEach(track => track.stop());
      setIsCameraActive(false);
    }
  };

  const takePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      if (context) {
        const video = videoRef.current;
        const canvas = canvasRef.current;

        // Ratio 3:4 pour portrait standard
        canvas.width = 600;
        canvas.height = 800;

        const videoWidth = video.videoWidth;
        const videoHeight = video.videoHeight;
        const aspectRatio = canvas.width / canvas.height;

        let sourceWidth = videoWidth;
        let sourceHeight = videoHeight;
        let sourceX = 0;
        let sourceY = 0;

        if (videoWidth / videoHeight > aspectRatio) {
          sourceWidth = videoHeight * aspectRatio;
          sourceX = (videoWidth - sourceWidth) / 2;
        } else {
          sourceHeight = videoWidth / aspectRatio;
          sourceY = (videoHeight - sourceHeight) / 2;
        }

        // Effet miroir car caméra frontale
        context.translate(canvas.width, 0);
        context.scale(-1, 1);

        context.drawImage(
          video,
          sourceX, sourceY, sourceWidth, sourceHeight,
          0, 0, canvas.width, canvas.height
        );

        const dataUrl = canvas.toDataURL('image/jpeg', 0.9);
        setPhoto(dataUrl);
        stopCamera();
      }
    }
  };

  const generateId = () => {
    const year = new Date().getFullYear();
    const random = Math.floor(100000 + Math.random() * 899999);
    return `UDPS-${year}-${random}`;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!photo) {
      alert("Veuillez capturer une photo pour le membre.");
      return;
    }
    setIsSubmitting(true);

    setTimeout(() => {
      const newMember: Member = {
        ...formData,
        id: generateId(),
        registrationDate: new Date().toISOString(),
        photoUrl: photo
      };

      onAddMember(newMember);
      setLastRegistered(newMember);

      setFormData({
        firstName: '',
        lastName: '',
        email: '',
        phone: '',
        birthDate: '',
        address: '',
      });
      setPhoto(null);
      setIsSubmitting(false);
    }, 800);
  };

  return (
    <div className="max-w-6xl mx-auto pb-12">
      <div className="grid lg:grid-cols-2 gap-10">

        {/* SECTION ENRÔLEMENT */}
        <div className="bg-white p-8 rounded-[2rem] shadow-xl shadow-slate-200/50 border border-slate-100">
          <div className="flex items-center justify-between mb-8">
            <div className="flex items-center gap-4">
              <div className="bg-red-600 p-3 rounded-2xl text-white shadow-lg shadow-red-100">
                <UserPlus size={28} />
              </div>
              <div>
                <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tighter">Nouvel Enrôlement</h2>
                <div className="flex items-center gap-2 mt-1">
                  <span className="h-1.5 w-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest leading-none">Terminal Biométrique Sécurisé</p>
                </div>
              </div>
            </div>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            {/* COMPOSANT DE CAPTURE PHOTO */}
            <div className="relative">
              <label className="block text-[11px] font-black text-slate-400 uppercase mb-3 tracking-[0.15em] ml-1">Photo d'identité obligatoire</label>

              <div className="relative aspect-[3/4] max-w-[280px] mx-auto group">
                {/* Cadre de design */}
                <div className="absolute inset-0 border-2 border-slate-100 rounded-[2.5rem] -m-2 pointer-events-none"></div>

                <div className="w-full h-full bg-slate-50 rounded-[2rem] overflow-hidden border-4 border-white shadow-2xl flex items-center justify-center relative">
                  {photo ? (
                    <div className="w-full h-full animate-in fade-in duration-500">
                      <img src={photo} className="w-full h-full object-cover" alt="Membre Capturé" />
                      <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity flex items-end justify-center pb-6">
                        <button 
                          type="button"
                          onClick={() => { setPhoto(null); startCamera(); }}
                          className="bg-white text-red-600 px-6 py-2.5 rounded-full font-black text-[10px] uppercase tracking-widest flex items-center gap-2 shadow-2xl hover:scale-105 active:scale-95 transition-all"
                        >
                          <RotateCcw size={14} /> Recommencer
                        </button>
                      </div>
                    </div>
                  ) : isCameraActive ? (
                    <div className="w-full h-full bg-black relative">
                      <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover scale-x-[-1]" />

                      {/* Overlay de guidage */}
                      <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
                        <div className="w-[85%] h-[75%] border-2 border-dashed border-white/30 rounded-[6rem]"></div>
                        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-4 h-4 border-2 border-white/50 rounded-full"></div>
                      </div>

                      {/* Bouton de Capture */}
                      <div className="absolute bottom-6 left-0 right-0 flex justify-center px-6">
                        <button 
                          type="button"
                          onClick={takePhoto}
                          className="group relative flex items-center justify-center"
                        >
                          <div className="absolute inset-0 bg-red-600 rounded-full blur-md opacity-40 group-hover:opacity-60 transition-opacity"></div>
                          <div className="relative w-16 h-16 bg-white rounded-full p-1 border-4 border-white shadow-2xl active:scale-90 transition-transform">
                            <div className="w-full h-full bg-red-600 rounded-full flex items-center justify-center">
                              <CameraIcon size={24} className="text-white" />
                            </div>
                          </div>
                        </button>
                      </div>
                    </div>
                  ) : (
                    <div className="flex flex-col items-center gap-4 text-slate-300">
                      <div className="w-20 h-20 bg-white rounded-3xl flex items-center justify-center shadow-lg border border-slate-50">
                        <Camera size={36} className="text-slate-200" />
                      </div>
                      <button 
                        type="button"
                        onClick={startCamera}
                        className="bg-red-600 text-white px-8 py-3 rounded-2xl font-black uppercase tracking-widest text-[11px] shadow-lg shadow-red-100 hover:bg-red-700 transition-all active:scale-95"
                      >
                        Activer Caméra
                      </button>
                    </div>
                  )}
                </div>
              </div>
              <canvas ref={canvasRef} className="hidden" />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider ml-1">Prénom</label>
                <input
                  required
                  type="text"
                  value={formData.firstName}
                  onChange={e => setFormData({...formData, firstName: e.target.value})}
                  className="w-full px-5 py-3.5 rounded-2xl bg-slate-50 border border-slate-100 focus:bg-white focus:ring-4 focus:ring-red-500/10 focus:border-red-500 outline-none transition-all font-semibold"
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider ml-1">Nom</label>
                <input
                  required
                  type="text"
                  value={formData.lastName}
                  onChange={e => setFormData({...formData, lastName: e.target.value})}
                  className="w-full px-5 py-3.5 rounded-2xl bg-slate-50 border border-slate-100 focus:bg-white focus:ring-4 focus:ring-red-500/10 focus:border-red-500 outline-none transition-all font-semibold"
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider ml-1">Téléphone</label>
                <input
                  required
                  type="tel"
                  placeholder="+243..."
                  value={formData.phone}
                  onChange={e => setFormData({...formData, phone: e.target.value})}
                  className="w-full px-5 py-3.5 rounded-2xl bg-slate-50 border border-slate-100 focus:bg-white focus:ring-4 focus:ring-red-500/10 focus:border-red-500 outline-none transition-all font-semibold"
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider ml-1">Email</label>
                <input
                  type="email"
                  value={formData.email}
                  onChange={e => setFormData({...formData, email: e.target.value})}
                  className="w-full px-5 py-3.5 rounded-2xl bg-slate-50 border border-slate-100 focus:bg-white focus:ring-4 focus:ring-red-500/10 focus:border-red-500 outline-none transition-all font-semibold"
                />
              </div>
            </div>

            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-wider ml-1">Adresse de Résidence</label>
              <textarea
                required
                rows={2}
                value={formData.address}
                onChange={e => setFormData({...formData, address: e.target.value})}
                className="w-full px-5 py-3.5 rounded-2xl bg-slate-50 border border-slate-100 focus:bg-white focus:ring-4 focus:ring-red-500/10 focus:border-red-500 outline-none transition-all font-semibold resize-none"
              />
            </div>

            <button
              disabled={isSubmitting || !photo}
              type="submit"
              className="w-full bg-red-600 hover:bg-red-700 disabled:bg-slate-100 disabled:text-slate-400 text-white font-black py-5 rounded-[1.5rem] shadow-xl shadow-red-100 transition-all uppercase tracking-[0.2em] text-xs flex items-center justify-center gap-3 active:scale-95"
            >
              {isSubmitting ? (
                <>
                  <RotateCcw className="animate-spin" size={18} />
                  Traitement Sécurisé...
                </>
              ) : 'Finaliser l\'Adhésion'}
            </button>
          </form>
        </div>

        {/* SECTION APERÇU / REÇU */}
        <div className="space-y-8">
          {lastRegistered ? (
            <div className="bg-white p-8 rounded-[2rem] shadow-2xl shadow-slate-200 border border-slate-100 animate-in fade-in zoom-in duration-500 sticky top-24">
              <div className="flex flex-col items-center">
