import React, { useState, useRef } from 'react';
import { Member } from '../types';
import { QRCodeSVG } from 'qrcode.react';
import { UserPlus, CheckCircle, Download, User, Camera, Mail, MessageCircle, RotateCcw, CameraIcon, ShieldCheck, Upload, FileImage } from 'lucide-react';

interface RegistrationAppProps {
  onAddMember: (member: Member) => void;
}

const RegistrationApp: React.FC<RegistrationAppProps> = ({ onAddMember }) => {
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    birthDate: '',
    address: '',
  });
  const [photo, setPhoto] = useState<string | null>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [lastRegistered, setLastRegistered] = useState<Member | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { 
          facingMode: 'user',
          width: { ideal: 1280 },
          height: { ideal: 720 }
        } 
      });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        setIsCameraActive(true);
      }
    } catch (err) {
      alert("Impossible d'accéder à la caméra. Veuillez vérifier les permissions.");
    }
  };

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
      tracks.forEach(track => track.stop());
      setIsCameraActive(false);
    }
  };

  const processImage = (imageElement: HTMLImageElement | HTMLVideoElement) => {
    if (canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      if (context) {
        const canvas = canvasRef.current;

        // Ratio 3:4 pour portrait standard PVC
        canvas.width = 600;
        canvas.height = 800;

        let sourceWidth, sourceHeight, sourceX, sourceY;

        if (imageElement instanceof HTMLVideoElement) {
          sourceWidth = imageElement.videoWidth;
          sourceHeight = imageElement.videoHeight;
        } else {
          sourceWidth = imageElement.width;
          sourceHeight = imageElement.height;
        }

        const aspectRatio = canvas.width / canvas.height;

        if (sourceWidth / sourceHeight > aspectRatio) {
          const newSourceWidth = sourceHeight * aspectRatio;
          sourceX = (sourceWidth - newSourceWidth) / 2;
          sourceWidth = newSourceWidth;
          sourceY = 0;
        } else {
          const newSourceHeight = sourceWidth / aspectRatio;
          sourceY = (sourceHeight - newSourceHeight) / 2;
          sourceHeight = newSourceHeight;
          sourceX = 0;
        }

        context.clearRect(0, 0, canvas.width, canvas.height);

        // Effet miroir uniquement pour la vidéo (caméra frontale)
        if (imageElement instanceof HTMLVideoElement) {
          context.translate(canvas.width, 0);
          context.scale(-1, 1);
        }

        context.drawImage(
          imageElement,
          sourceX, sourceY, sourceWidth, sourceHeight,
          0, 0, canvas.width, canvas.height
        );

        // Reset transformation si miroir appliqué
        if (imageElement instanceof HTMLVideoElement) {
          context.setTransform(1, 0, 0, 1, 0, 0);
        }

        const dataUrl = canvas.toDataURL('image/jpeg', 0.9);
        setPhoto(dataUrl);
        if (imageElement instanceof HTMLVideoElement) stopCamera();
      }
    }
  };

  const takePhoto = () => {
    if (videoRef.current) {
      processImage(videoRef.current);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const img = new Image();
        img.onload = () => {
          processImage(img);
        };
        img.src = event.target?.result as string;
      };
      reader.readAsDataURL(file);
    }
