                </div>
              </div>
            </div>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            {/* COMPOSANT DE CAPTURE PHOTO */}
            <div className="relative">
              <label className="block text-[11px] font-black text-slate-400 uppercase mb-3 tracking-[0.15em] ml-1">Photo d'identité (Capture ou Import)</label>

              <div className="relative aspect-[3/4] max-w-[280px] mx-auto group">
                <div className="absolute inset-0 border-2 border-slate-100 rounded-[2.5rem] -m-2 pointer-events-none"></div>

                <div className="w-full h-full bg-slate-50 rounded-[2rem] overflow-hidden border-4 border-white shadow-2xl flex items-center justify-center relative">
                  {photo ? (
                    <div className="w-full h-full animate-in fade-in duration-500">
                      <img src={photo} className="w-full h-full object-cover" alt="Membre Capturé" />
                      <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity flex items-end justify-center pb-6 gap-2">
                        <button 
                          type="button"
                          onClick={() => { setPhoto(null); startCamera(); }}
                          className="bg-white text-red-600 px-4 py-2 rounded-full font-black text-[9px] uppercase tracking-widest flex items-center gap-2 shadow-2xl hover:scale-105 transition-all"
                        >
                          <RotateCcw size={12} /> Caméra
                        </button>
                        <button 
                          type="button"
                          onClick={() => fileInputRef.current?.click()}
                          className="bg-white text-slate-800 px-4 py-2 rounded-full font-black text-[9px] uppercase tracking-widest flex items-center gap-2 shadow-2xl hover:scale-105 transition-all"
                        >
                          <Upload size={12} /> Import
                        </button>
                      </div>
                    </div>
                  ) : isCameraActive ? (
                    <div className="w-full h-full bg-black relative">
                      <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover scale-x-[-1]" />
