                  </div>

                  <div className="bg-white p-6 rounded-[2rem] shadow-[0_0_50px_rgba(255,255,255,0.1)] relative group">
                    <QRCodeSVG 
                      value={lastRegistered.id} 
                      size={200} 
                      level="H" 
                      includeMargin={false}
                      imageSettings={{
                        src: "https://upload.wikimedia.org/wikipedia/commons/thumb/d/d3/Shield_font_awesome.svg/512px-Shield_font_awesome.svg.png",
                        x: undefined,
                        y: undefined,
                        height: 40,
                        width: 40,
                        excavate: true,
                      }}
                    />
