              <div>
                <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tighter">Enrôlement</h2>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">UDPS Biométrie</p>
              </div>
            </div>
            <div className="text-right">
              <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">ID Prévu</p>
              <div className="bg-slate-900 text-white px-3 py-1 rounded-lg font-mono text-xs font-bold">{currentGeneratedId}</div>
            </div>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="relative group">
              <div className="relative aspect-[3/4] max-w-[220px] mx-auto">
                <div className="w-full h-full bg-slate-50 rounded-[2rem] overflow-hidden border-4 border-white shadow-2xl flex items-center justify-center relative">
                  {photo ? (
                    <div className="w-full h-full animate-in fade-in">
                      <img src={photo} className="w-full h-full object-cover" alt="Portrait" />
                      <button type="button" onClick={() => { setPhoto(null); startCamera(); }} className="absolute bottom-4 left-1/2 -translate-x-1/2 bg-white text-red-600 p-2 rounded-full shadow-lg"><RotateCcw size={16} /></button>
                    </div>
                  ) : isCameraActive ? (
                    <div className="w-full h-full bg-black relative">
                      <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover scale-x-[-1]" />
                      <button type="button" onClick={takePhoto} className="absolute bottom-4 left-1/2 -translate-x-1/2 w-12 h-12 bg-white rounded-full p-1 border-4 border-white shadow-2xl"><div className="w-full h-full bg-red-600 rounded-full" /></button>
                    </div>
                  ) : (
                    <div className="flex flex-col items-center gap-3">
                      <User size={40} className="text-slate-200" />
                      <div className="flex flex-col gap-2">
                        <button type="button" onClick={startCamera} className="bg-red-600 text-white px-4 py-2 rounded-xl font-bold text-[10px] uppercase tracking-wider">Caméra</button>
                        <button type="button" onClick={() => fileInputRef.current?.click()} className="bg-white text-slate-600 border px-4 py-2 rounded-xl font-bold text-[10px] uppercase tracking-wider">Importer</button>
                      </div>
                    </div>
                  )}
                </div>
              </div>
              <input type="file" ref={fileInputRef} onChange={handleFileUpload} accept="image/*" className="hidden" />
