            <button disabled={isSubmitting || !photo} type="submit" className="w-full bg-red-600 hover:bg-red-700 disabled:bg-slate-100 text-white font-black py-4 rounded-2xl shadow-xl transition-all uppercase tracking-[0.2em] text-xs flex items-center justify-center gap-3">
