import React, { useState, useRef, useMemo } from 'react';
import { Member } from '../types';
import { QRCodeSVG } from 'qrcode.react';
import { UserPlus, CheckCircle, Download, User, Camera, Mail, MessageCircle, RotateCcw, CameraIcon, ShieldCheck, Upload, Fingerprint, IdCard, Copy, ScanLine, Globe, MapPin, Users } from 'lucide-react';

interface RegistrationAppProps {
  onAddMember: (member: Member) => void;
}

const RegistrationApp: React.FC<RegistrationAppProps> = ({ onAddMember }) => {
  const [formData, setFormData] = useState({
    lastName: '',
    postName: '',
    firstName: '',
    sexe: 'M',
    birthDate: '',
    country: 'RD Congo',
    cityProvince: '',
    category: 'Combattant',
    federation: '',
    phone: '',
    email: '',
  });

  const [photo, setPhoto] = useState<string | null>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [lastRegistered, setLastRegistered] = useState<Member | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const qrRef = useRef<SVGSVGElement>(null);

  const currentGeneratedId = useMemo(() => {
    if (!formData.firstName && !formData.lastName) return "UDPS-TEMP-XXXXXX";
    const year = new Date().getFullYear();
    const random = Math.floor(100000 + Math.random() * 899999);
    return `UDPS-${year}-${random}`;
  }, [lastRegistered]);

  const downloadQRCode = () => {
    const svg = qrRef.current;
    if (!svg) return;
    const svgData = new XMLSerializer().serializeToString(svg);
    const canvas = document.createElement("canvas");
    const ctx = canvas.getContext("2d");
    const img = new Image();
    img.onload = () => {
      canvas.width = img.width;
      canvas.height = img.height;
      ctx?.drawImage(img, 0, 0);
      const pngFile = canvas.toDataURL("image/png");
      const downloadLink = document.createElement("a");
      downloadLink.download = `QR_${lastRegistered?.id}.png`;
      downloadLink.href = pngFile;
      downloadLink.click();
    };
    img.src = "data:image/svg+xml;base64," + btoa(svgData);
  };

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'user', width: { ideal: 1280 }, height: { ideal: 720 } } 
      });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        setIsCameraActive(true);
      }
    } catch (err) {
      alert("Impossible d'accéder à la caméra.");
    }
  };

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
      tracks.forEach(track => track.stop());
      setIsCameraActive(false);
    }
  };

  const processImage = (imageElement: HTMLImageElement | HTMLVideoElement) => {
    if (canvasRef.current) {
      const canvas = canvasRef.current;
      const context = canvas.getContext('2d');
      if (context) {
        canvas.width = 600;
        canvas.height = 800;
        let sw, sh, sx, sy;
        if (imageElement instanceof HTMLVideoElement) {
          sw = imageElement.videoWidth; sh = imageElement.videoHeight;
        } else {
          sw = imageElement.width; sh = imageElement.height;
        }
        const aspect = canvas.width / canvas.height;
        if (sw / sh > aspect) {
          const nsw = sh * aspect; sx = (sw - nsw) / 2; sw = nsw; sy = 0;
        } else {
          const nsh = sw / aspect; sy = (sh - nsh) / 2; sh = nsh; sx = 0;
        }
        context.clearRect(0, 0, canvas.width, canvas.height);
        if (imageElement instanceof HTMLVideoElement) {
          context.translate(canvas.width, 0); context.scale(-1, 1);
        }
        context.drawImage(imageElement, sx, sy, sw, sh, 0, 0, canvas.width, canvas.height);
        if (imageElement instanceof HTMLVideoElement) context.setTransform(1, 0, 0, 1, 0, 0);
        setPhoto(canvas.toDataURL('image/jpeg', 0.9));
        if (imageElement instanceof HTMLVideoElement) stopCamera();
      }
    }
  };

  const takePhoto = () => videoRef.current && processImage(videoRef.current);
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        const img = new Image();
        img.onload = () => processImage(img);
        img.src = ev.target?.result as string;
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!photo) { alert("Photo requise."); return; }
    setIsSubmitting(true);
    setTimeout(() => {
      const memberData: Member = { 
        ...formData, 
        id: currentGeneratedId, 
        registrationDate: new Date().toISOString(), 
        photoUrl: photo 
      };
      onAddMember(memberData);
      setLastRegistered(memberData);
      setFormData({ 
        lastName: '', postName: '', firstName: '', sexe: 'M', birthDate: '', 
        country: 'RD Congo', cityProvince: '', category: 'Combattant', 
        federation: '', phone: '', email: '' 
      });
      setPhoto(null);
      setIsSubmitting(false);
    }, 800);
  };

  return (
    <div className="max-w-6xl mx-auto pb-12">
      <div className="grid lg:grid-cols-2 gap-10">
        <div className="bg-white p-8 rounded-[2.5rem] shadow-xl border border-slate-100">
          <div className="flex items-center justify-between mb-8">
            <div className="flex items-center gap-4">
              <div className="bg-red-600 p-3 rounded-2xl text-white shadow-lg"><UserPlus size={28} /></div>
              <div>
                <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tighter">Enrôlement</h2>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">UDPS Biométrie</p>
              </div>
            </div>
            <div className="text-right">
              <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">ID Prévu</p>
              <div className="bg-slate-900 text-white px-3 py-1 rounded-lg font-mono text-xs font-bold">{currentGeneratedId}</div>
            </div>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            {/* Capture Photo */}
            <div className="relative group mb-8">
              <div className="relative aspect-[3/4] max-w-[180px] mx-auto">
                <div className="w-full h-full bg-slate-50 rounded-[2rem] overflow-hidden border-4 border-white shadow-2xl flex items-center justify-center relative">
                  {photo ? (
                    <div className="w-full h-full animate-in fade-in">
                      <img src={photo} className="w-full h-full object-cover" alt="Portrait" />
                      <button type="button" onClick={() => { setPhoto(null); startCamera(); }} className="absolute bottom-4 left-1/2 -translate-x-1/2 bg-white text-red-600 p-2 rounded-full shadow-lg"><RotateCcw size={16} /></button>
                    </div>
                  ) : isCameraActive ? (
                    <div className="w-full h-full bg-black relative">
                      <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover scale-x-[-1]" />
                      <button type="button" onClick={takePhoto} className="absolute bottom-4 left-1/2 -translate-x-1/2 w-12 h-12 bg-white rounded-full p-1 border-4 border-white shadow-2xl"><div className="w-full h-full bg-red-600 rounded-full" /></button>
                    </div>
                  ) : (
                    <div className="flex flex-col items-center gap-3">
                      <User size={40} className="text-slate-200" />
                      <div className="flex flex-col gap-2">
                        <button type="button" onClick={startCamera} className="bg-red-600 text-white px-4 py-2 rounded-xl font-bold text-[10px] uppercase tracking-wider">Caméra</button>
                        <button type="button" onClick={() => fileInputRef.current?.click()} className="bg-white text-slate-600 border px-4 py-2 rounded-xl font-bold text-[10px] uppercase tracking-wider">Importer</button>
                      </div>
                    </div>
                  )}
                </div>
              </div>
              <input type="file" ref={fileInputRef} onChange={handleFileUpload} accept="image/*" className="hidden" />
              <canvas ref={canvasRef} className="hidden" />
            </div>

            {/* Identité */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nom</label>
                <input required type="text" value={formData.lastName} onChange={e => setFormData({...formData, lastName: e.target.value})} className="w-full px-4 py-3 rounded-xl bg-slate-50 border outline-none font-bold focus:border-red-500" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Postnom</label>
                <input required type="text" value={formData.postName} onChange={e => setFormData({...formData, postName: e.target.value})} className="w-full px-4 py-3 rounded-xl bg-slate-50 border outline-none font-bold focus:border-red-500" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Prénom</label>
                <input required type="text" value={formData.firstName} onChange={e => setFormData({...formData, firstName: e.target.value})} className="w-full px-4 py-3 rounded-xl bg-slate-50 border outline-none font-bold focus:border-red-500" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Sexe</label>
                <select value={formData.sexe} onChange={e => setFormData({...formData, sexe: e.target.value})} className="w-full px-4 py-3 rounded-xl bg-slate-50 border outline-none font-bold focus:border-red-500">
                  <option value="M">Masculin (M)</option>
                  <option value="F">Féminin (F)</option>
                </select>
              </div>
              <div className="space-y-1">
