              <div>
                <h1 className="text-xl font-black text-blue-900 tracking-tighter uppercase leading-none">UDPS</h1>
                <p className="text-[10px] font-black text-red-600 uppercase tracking-widest mt-1">Base de données Nationale</p>
              </div>
            </div>

            <nav className="flex gap-2 bg-slate-100 p-1.5 rounded-2xl">
              <button
                onClick={() => setView(AppView.REGISTRATION)}
                className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-black transition-all uppercase tracking-tighter ${
                  view === AppView.REGISTRATION 
                  ? 'bg-white text-blue-900 shadow-sm' 
                  : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                <UserPlus size={18} />
                Enrôlement
