import { Member, CentralDatabase } from '../types';

const DB_KEY = 'udps_system_prod_v1';
const DB_VERSION = '1.0.0';

export const dbService = {
  // Simule une requête GET vers un serveur Cloud
  async getDatabase(): Promise<CentralDatabase> {
    return new Promise((resolve) => {
      setTimeout(() => {
        const saved = localStorage.getItem(DB_KEY);
        if (saved) {
          try {
            resolve(JSON.parse(saved));
          } catch (e) {
            console.error("Erreur de lecture DB", e);
          }
        }
        resolve({
          version: DB_VERSION,
          lastUpdated: new Date().toISOString(),
          members: []
        });
      }, 800); // Simulation de latence réseau
    });
  },

  // Simule une requête POST/PUT vers un serveur Cloud
  async saveMember(member: Member): Promise<boolean> {
    return new Promise((resolve) => {
      setTimeout(() => {
        const saved = localStorage.getItem(DB_KEY);
        let db: CentralDatabase = saved ? JSON.parse(saved) : { 
          version: DB_VERSION, 
          lastUpdated: '', 
          members: [] 
        };

        db.members = [member, ...db.members];
        db.lastUpdated = new Date().toISOString();

        localStorage.setItem(DB_KEY, JSON.stringify(db));
        resolve(true);
      }, 1000);
    });
  },

  // Simule une synchronisation forcée avec le Cloud
  async syncWithCloud(): Promise<{ success: boolean; count: number }> {
    return new Promise((resolve) => {
      setTimeout(() => {
        const saved = localStorage.getItem(DB_KEY);
        const db = saved ? JSON.parse(saved) : { members: [] };
        resolve({ success: true, count: db.members.length });
      }, 2000);
    });
  }
};

